class Solution {
public:
    int findLength(vector<int>& a, vector<int>& b) {
        int m=a.size(), n=b.size(), ans=0;
        vector<vector<int>> dp(m+1, vector<int>(n+1));
        for(int i=1;i<=m;i++) for(int j=1;j<=n;j++){
            if(a[i-1]==b[j-1]){ dp[i][j]=dp[i-1][j-1]+1; ans=max(ans,dp[i][j]); }
        }
        return ans;
    }
};

